import java.math.BigDecimal;

public class OrderValidator {
    public static int validateOrder(Order order) {
        // ① 空值校验，优先级最高
        if (order == null || order.getOrder_amount() == null || order.getCoupon_amount() == null || order.getUser_balance() == null) {
            return 1001;
        }

        // 转换为BigDecimal避免精度问题，用字符串构造防止double本身的精度误差
        BigDecimal orderAmt = new BigDecimal(String.valueOf(order.getOrder_amount()));
        BigDecimal couponAmt = new BigDecimal(String.valueOf(order.getCoupon_amount()));
        BigDecimal userBal = new BigDecimal(String.valueOf(order.getUser_balance()));

        // ② 金额非负校验
        if (orderAmt.compareTo(BigDecimal.ZERO) < 0 || couponAmt.compareTo(BigDecimal.ZERO) < 0 || userBal.compareTo(BigDecimal.ZERO) < 0) {
            return 1002;
        }

        // ③ 优惠券规则校验，同优先级内先校验小数位
        // 校验优惠券小数位是否超过2位（去除末尾无意义0，符合“最多保留2位小数”要求）
        if (couponAmt.stripTrailingZeros().scale() > 2) {
            return 1004;
        }
        // 校验优惠券是否超过订单金额的80%
        BigDecimal maxCoupon = orderAmt.multiply(new BigDecimal("0.8"));
        if (couponAmt.compareTo(maxCoupon) > 0) {
            return 1003;
        }

        // ④ 余额规则校验，先校验余额小数位
        if (userBal.stripTrailingZeros().scale() > 2) {
            return 1004;
        }
        // 校验余额是否足够支付应付金额
        BigDecimal needPay = orderAmt.subtract(couponAmt);
        if (userBal.compareTo(needPay) < 0) {
            return 1005;
        }

        // ⑤ 订单状态校验
        if (!"UNPAID".equals(order.getOrder_status())) {
            return 1006;
        }

        // ⑥ VIP特殊规则校验
        if (order.isIs_vip() && orderAmt.compareTo(new BigDecimal("10")) < 0) {
            return 1007;
        }

        // 所有校验通过
        return 0;
    }
}
